import json

D = lambda i,t,s,e,n,c,nx: {"id":i,"text":t,"speaker":"我","avatar":"厂","score":s,"triggeredEvent":e,"historicalNote":n,"consequence":c,"nextActId":nx}
A = lambda i,t,k,tm,s,n,dls: {"id":i,"title":t,"isKeyAct":k,"timeMarker":tm,"sceneDescription":s,"npcDialogues":n,"dialogues":dls}
N = lambda sp,tx,av: {"speaker":sp,"text":tx,"avatar":av}

acts = []

# 14
acts.append(A("act-14","经济危机",False,"1847年",
"1847年，一场严重的经济危机席卷了整个欧洲。工厂倒闭，工人失业，社会矛盾急剧激化。你的工厂也陷入了困境，订单减少，资金链紧张。你必须想办法渡过难关。",
[N("账房托马斯","老板，情况不妙啊。这个月的订单减少了一半，再这样下去，我们的资金链就要断了。","托"),N("失业工人吉姆","老板，求求你了，给我一份工作吧，我家里已经好几天没开锅了。","吉")],
[D("d1","我要缩减生产，裁减工人，先活下去再说。",65,"你决定缩减生产，裁减了大量工人。虽然降低了成本，但看着那些失业的工人，你心里也不好受。更糟糕的是，社会越来越动荡了。","1847年经济危机是资本主义世界第一次全球性的经济危机。危机导致大量工厂倒闭，工人失业，社会矛盾急剧激化。这场危机也为1848年革命埋下了伏笔。","缩减生产，裁减工人","act-15"),
D("d2","我绝不裁员，宁愿自己少赚点，也要保住工人的饭碗。",90,"你决定绝不裁员，宁愿减少利润，甚至亏损，也要保住工人的工作。工人们非常感动，更加努力地工作，你们一起熬过了难关。","在经济危机中，也有一些有良知的企业家选择与工人共渡难关。这种做法虽然短期内会减少利润，但能够赢得工人的信任和忠诚。","共渡难关，赢得信任","act-15"),
D("d3","我要开拓新市场，东方的殖民地国家还有很大潜力。",85,"你决定开拓新市场，把目光投向了印度、中国等东方殖民地国家。虽然路途遥远，但那里有巨大的市场潜力，帮你渡过了危机。","工业革命后，资本主义国家急需开拓海外市场。殖民地成为它们的原料产地和商品倾销市场。殖民扩张是资本主义发展的必然结果。","开拓东方，海外市场","act-15"),
D("d4","我要搞技术创新，用新产品打开销路。",88,"你决定加大技术研发投入，开发新产品。虽然危机期间搞研发风险很大，但你的新产品在市场上大获成功，反而在危机中发展壮大了。","经济危机既是挑战也是机遇。在危机中坚持创新的企业，往往能够脱颖而出，获得更大的发展。技术进步是企业的核心竞争力。","技术创新，化危为机","act-15"),
D("d5","我要联合其他工厂主，一起稳定市场价格。",75,"你联合了其他几家大工厂主，成立了行业协会，共同稳定市场价格。这虽然缓解了恶性竞争，但也形成了垄断，损害了消费者的利益。","经济危机期间，资本家往往会联合起来，通过成立卡特尔、托拉斯等组织来稳定价格，维护共同利益。垄断是资本主义发展到一定阶段的产物。","联合垄断，稳定市场","act-15"),
D("d6","我要把工厂卖掉，带着钱去乡下过安稳日子。",62,"你对工业生产感到厌倦，决定卖掉工厂，带着钱去乡下过安稳日子。虽然避开了危机，但你也错过了发展的机遇。","面对经济危机，有些人选择退出竞争，过安稳的生活。这是一种保守但稳妥的选择。","卖掉工厂，隐居乡间","act-15"),
D("d7","我要投资铁路和基建，危机时期正好抄底。",82,"你看到了危机中的机遇，开始投资铁路和基础设施建设。地价和原材料都很便宜，等危机过去，这些投资会带来丰厚的回报。","危机往往伴随着抄底的机会。有远见的投资者会在别人恐慌的时候贪婪，在危机中布局，等待经济复苏时获得丰厚回报。","危机抄底，布局未来","act-15"),
D("d8","我要向政府求助，要求政府救助我们。",70,"你向政府求助，要求政府出台救助政策。政府确实出台了一些扶持政策，但力度有限，主要还是得靠自己。","经济危机期间，企业往往会向政府求助。但政府的救助是有限的，企业最终还是要靠自己的力量走出困境。","求助政府，政策扶持","act-15"),
D("d9","这是资本主义的固有矛盾，我要研究一下社会主义理论。",80,"经历了这场危机，你开始反思资本主义制度的弊端。你读了一些社会主义者的著作，对社会问题有了新的认识。","经济危机暴露了资本主义制度的内在矛盾。许多人在危机中开始反思，转而研究社会主义理论，寻求社会问题的解决方案。","反思制度，研究社会主义","act-15")]))

# 15 - 关键幕3
acts.append(A("act-15","共产党宣言",True,"1848年",
"1848年，马克思和恩格斯发表了《共产党宣言》，标志着马克思主义的诞生。宣言阐述了资本主义必然灭亡、共产主义必然胜利的历史规律，号召全世界无产者联合起来。这本小册子在工人中迅速传播，也引起了资产阶级的恐慌。",
[N("工人代表约瑟夫","老板，你读过《共产党宣言》吗？它说我们工人阶级才是历史的创造者，资产阶级注定要灭亡。","约"),N("工厂主同行卡尔","这些共产主义者简直是异端邪说！必须把他们抓起来，不然我们都会被吊在路灯上！","卡")],
[D("d1","荒谬！无产阶级专政就是要抢我们的财产！必须严厉禁止！",62,"你怒斥《共产党宣言》是异端邪说，要求政府严厉禁止共产主义思想的传播。你还出钱资助反共宣传，试图阻止马克思主义的传播。","《共产党宣言》发表后，遭到了各国资产阶级的围攻和禁止。但真理是封不住的，马克思主义在工人运动中迅速传播，成为无产阶级解放斗争的思想武器。","敌视宣言，极力反对","act-16"),
D("d2","我觉得有些地方说得有道理，值得认真研究。",85,"你认真阅读了《共产党宣言》，虽然不同意其中的革命主张，但承认它对资本主义弊病的分析有道理。你开始思考如何改良资本主义，避免革命。","《共产党宣言》深刻分析了资本主义的内在矛盾。许多有识之士，包括一些资产阶级人士，都承认马克思对资本主义的批判有其合理之处。","认真研读，承认合理","act-16"),
D("d3","我要改善工人待遇，让他们过得好一点，这样就不会闹革命了。",88,"读完《共产党宣言》后，你意识到工人阶级的贫困是社会动荡的根源。你决定主动改善工人待遇，提高工资，缩短工时，试图用改良来避免革命。","面对工人运动的高涨和马克思主义的传播，一些有远见的资产阶级认识到，必须做出某些让步，改善工人待遇，以缓和阶级矛盾，维护资本主义制度的稳定。","主动改良，缓和矛盾","act-16"),
D("d4","这书太有煽动性了，我要收起来不让工人们看到。",68,"你觉得《共产党宣言》太有煽动性了，千方百计不让工人们看到。但越是禁止，人们越是好奇，这本书在地下流传得越来越广。","历史上，任何进步思想的传播都会遭到反动势力的压制。但压制往往适得其反，反而会让更多的人去了解和传播这些思想。","极力封锁，地下传播","act-15b"),
D("d5","我想见见马克思和恩格斯，当面和他们辩论。",82,"你对这两位思想家很好奇，想当面和他们辩论。通过交流，你虽然没有改变立场，但对马克思主义有了更深入的了解，也更加尊重这两位思想家。","马克思和恩格斯不仅是伟大的理论家，也乐于与不同观点的人交流。他们的思想是在辩论和斗争中不断发展完善的。","当面辩论，深入了解","act-16"),
D("d6","我要写文章批判《共产党宣言》，从理论上驳倒它。",75,"你决定写文章批判《共产党宣言》，试图从理论上驳倒马克思主义。但你很快发现，马克思的理论体系非常严密，不是那么容易驳倒的。","马克思主义从诞生之日起，就不断遭到各种批判和攻击。但它在斗争中不断发展，显示出强大的生命力。","撰文批判，难以驳倒","act-16"),
D("d7","我觉得这书说得太对了！我要加入工人运动！",92,"你被《共产党宣言》深深震撼了，认识到资本主义的历史局限性。你毅然放弃了工厂主的身份，投身于工人运动，成为了一名社会主义者。","历史上，确实有一些出身资产阶级的有识之士，在认识到真理后，毅然背叛了自己的阶级，投身于无产阶级解放事业。恩格斯就是其中的杰出代表。","思想转变，投身革命","act-16"),
D("d8","这都是些什么乱七八糟的，我才不关心呢。",65,"你对政治理论不感兴趣，觉得这些都是空谈，不如多赚点钱实在。你继续经营你的工厂，对周围发生的思想变革视而不见。","在历史大变革时期，并不是所有人都能敏锐地意识到时代的变化。有些人只关心自己的生活，对宏大的历史进程漠不关心。","不关心政治，只顾赚钱","act-16"),
D("d9","我要去巴黎看看，那里的革命形势怎么样。",78,"你决定去巴黎考察革命形势。1848年革命的浪潮让你深受震撼，你对历史发展的方向有了新的认识。","1848年，欧洲爆发了大规模的革命运动。法国二月革命推翻了七月王朝，建立了第二共和国。这场革命对整个欧洲都产生了深远的影响。","考察巴黎，见证革命","act-16")]))

# 15b
acts.append(A("act-15b","思想传播",False,"1850年",
"虽然你极力封锁，但马克思主义的思想还是在工人中传播开来。工人们开始组织起来，成立工会，为争取自身权益而斗争。你发现，单纯的压制是行不通的，必须想新的办法。",
[N("工会代表布朗","先生，我们已经成立了工会。我们要求提高工资，缩短工时，改善工作条件。希望你能认真考虑我们的要求。","布"),N("保守朋友亨利","这些工人越来越不像话了！都是那些共产主义小册子闹的。应该把工会取缔掉！","亨")],
[D("d1","我愿意和工会谈判，合理的要求我会考虑。",88,"你决定承认工会的合法地位，愿意与工会进行平等谈判。经过谈判，你满足了工人的部分合理要求。虽然增加了一些成本，但工厂的劳资关系改善了很多。","承认工会、进行集体谈判是劳资关系进步的表现。随着工人运动的发展，资产阶级逐渐认识到，与工会合作比压制工会更有利于维护社会稳定。","承认工会，平等谈判","act-16"),
D("d2","绝不承认工会！谁参加工会就解雇谁！",60,"你坚决不承认工会，还威胁要解雇参加工会的工人。这激起了工人的强烈反抗，一场大罢工爆发了，你的工厂损失惨重。","早期工会常常遭到资产阶级的敌视和镇压。但压制往往适得其反，只会激起工人更强烈的反抗。","压制工会，引发罢工","act-16"),
D("d3","我要成立公司工会，把工人运动控制在我手里。",72,"你想出了一个办法——成立一个由公司控制的工会，这样既满足了工人组织起来的愿望，又能把运动控制在自己手里。","黄色工会是资本家控制的工会组织。它们表面上代表工人利益，实际上是为资本家服务的，目的是防止真正的革命工会出现。","公司工会，控制运动","act-16"),
D("d4","我要改善工人的福利待遇，让他们不需要工会。",85,"你决定从根源入手，大力改善工人的福利待遇。你提高工资，缩短工时，还办了工人子弟学校和医院。工人们的生活改善了，对工会的需求自然就没那么强烈了。","改善工人待遇是缓和劳资矛盾的根本方法。一些有远见的资本家认识到，让工人过上体面的生活，不仅有利于社会稳定，也有利于提高生产效率。","改善福利，缓和矛盾","act-16"),
D("d5","我要分化工人，拉拢工人贵族，让他们帮我说话。",70,"你采取了分化策略，提高技术工人的待遇，培养工人贵族，让他们成为你在工人中的代言人。这招确实有效，工人运动的战斗力被削弱了。","工人贵族是资产阶级化的工人阶层。资产阶级通过提高部分熟练工人的待遇，来分化工人阶级，削弱工人运动的战斗力。这是资产阶级常用的统治手段。","分化工人，培养贵族","act-16"),
D("d6","我要研究一下社会主义，看看他们到底说的有没有道理。",82,"你决定系统地研究社会主义理论，看看这些思想为什么有这么大的吸引力。通过研究，你虽然没有成为社会主义者，但对工人运动有了更深的理解。","知己知彼，百战不殆。要对付工人运动，首先要了解工人运动的理论基础。一些资产阶级学者就是在研究社会主义的过程中，对资本主义制度进行了反思。","研究理论，深化认识","act-16"),
D("d7","我要和其他工厂主联合起来，共同对付工会。",75,"你联合了其他工厂主，成立了雇主协会，共同对付工会。你们统一立场，协调行动，在与工会的谈判中占据了有利地位。","面对工会的崛起，资本家们也联合起来，成立雇主协会，维护共同利益。劳资双方的组织化程度都在提高。","雇主联合，共同对付","act-16"),
D("d8","我要引进更多机器，用机器代替人工，减少对工人的依赖。",88,"你决定加大技术投入，用更多的机器代替人工。这样既提高了生产效率，又减少了对工人的依赖，削弱了工会的谈判力量。","技术进步是一把双刃剑。它既提高了生产力，又会对就业和劳资关系产生深远影响。用机器代替人工，是资本家对付工人运动的常用手段之一。","机器换人，削弱工会","act-16"),
D("d9","算了，我把工厂卖了，去做投资，不用再和工人打交道。",65,"你厌倦了和工人打交道的日子，决定卖掉工厂，转行做投资。虽然不用再面对劳资矛盾了，但你也脱离了生产一线。","随着资本主义的发展，资本所有权和经营权逐渐分离。很多资本家脱离了生产一线，成为单纯的食利者。","卖掉工厂，转行投资","act-16")]))

# 16
acts.append(A("act-16","第一国际",False,"1864年",
"1864年，第一国际（国际工人协会）在伦敦成立。马克思是第一国际的灵魂人物。第一国际的成立标志着工人运动进入了国际联合的新阶段。各国工人阶级开始联合起来，共同反抗资产阶级的压迫。",
[N("工会代表威廉","先生，我们加入了第一国际。全世界的工人都在联合起来，资产阶级的统治不会长久了。","威"),N("工厂主同行布朗","第一国际是个危险的组织！各国政府都应该取缔它，不然我们都要完蛋！","布")],
[D("d1","第一国际太可怕了，我要向政府施压，取缔这个组织。",62,"你对第一国际的成立感到恐惧，极力向政府施压，要求取缔这个危险的组织。你还出钱资助反共活动，试图阻止国际工人运动的发展。","第一国际成立后，遭到了各国资产阶级的敌视和迫害。但国际工人联合的趋势是不可阻挡的，第一国际推动了各国工人运动的发展。","敌视第一国际，要求取缔","act-17"),
D("d2","我倒要看看，他们能闹出什么花样来。",70,"你对第一国际持观望态度，想看看他们到底有多大能耐。你并没有主动去镇压，只是在一旁观察局势的发展。","第一国际成立初期，很多资产阶级并没有把它放在眼里。但随着工人运动的发展，他们逐渐意识到了第一国际的力量。","观望态度，冷眼旁观","act-17"),
D("d3","我要改善工人待遇，不让他们被第一国际煽动起来。",85,"你意识到，要防止工人被第一国际吸引，最好的办法是改善工人待遇，让他们对现状满意。你主动提高工资，缩短工时，改善工作条件。","面对工人运动的高涨，一些有远见的资产阶级选择主动改良，通过改善工人待遇来缓和阶级矛盾，防止革命的发生。","主动改良，预防革命","act-17"),
D("d4","我想见见第一国际的人，听听他们到底怎么说。",82,"你对第一国际很好奇，决定亲自接触一下他们的成员。通过交流，你对工人运动有了更深入的了解，也更加理解工人的诉求。","了解对手是制定策略的前提。一些开明的资产阶级人士愿意接触工人运动的领袖，通过对话来增进了解，化解矛盾。","亲自接触，增进了解","act-17"),
D("d5","我要支持第一国际内部的温和派，打压激进派。",75,"你采取了分化瓦解的策略，暗中支持第一国际内部的改良派，打压激进的革命派。你试图把工人运动引向对资产阶级无害的方向。","资产阶级对付工人运动，历来有两手策略：一手是镇压，一手是分化。他们总是试图拉拢改良派，孤立革命派。","分化瓦解，拉拢温和派","act-17"),
D("d6","我担心第一国际会引发革命，准备转移财产。",68,"你对第一国际的发展感到担忧，担心会引发社会主义革命。你开始把财产转移到国外，为自己留后路。","面对工人运动的高涨，一些资本家会感到恐慌，选择转移财产甚至移民。这反映了资产阶级对革命的恐惧。","恐慌担忧，转移财产","act-17"),
D("d7","我认为工人有结社的权利，第一国际的存在是合理的。",88,"你认为工人阶级有结社自由，第一国际的存在是合理的。虽然你不认同他们的全部主张，但你尊重他们的权利。你的开明态度赢得了工人的好感。","结社自由是基本人权之一。随着民主制度的发展，越来越多的人承认工人有组织工会和政党的权利。","承认权利，态度开明","act-17"),
D("d8","这和我没关系，我做我的生意，他们搞他们的运动。",70,"你对政治不感兴趣，觉得第一国际和你没什么关系。你继续埋头做生意，对工人运动的发展漠不关心。","并不是所有人都关心政治。有些企业家专注于商业活动，对社会运动和政治斗争不感兴趣。","漠不关心，只顾生意","act-17"),
D("d9","我要去日内瓦参加第一国际的代表大会，亲眼看看。",78,"你决定去日内瓦参加第一国际的代表大会，亲眼看看这个组织到底是怎么运作的。这次经历让你大开眼界，对国际工人运动有了直观的认识。","第一国际每年召开代表大会，各国工人代表齐聚一堂，共同讨论工人运动的重大问题。这些大会推动了国际工人运动的团结和发展。","亲历大会，大开眼界","act-17")]))

# 17
acts.append(A("act-17","普法战争",False,"1870年",
"1870年，普法战争爆发。法国战败，拿破仑三世被俘。这场战争彻底改变了欧洲的政治格局。普鲁士统一了德国，成为欧洲大陆的新兴强国。而法国则陷入了动荡和危机之中。",
[N("商人朋友詹姆斯","普法战争结束了，法国惨败。听说巴黎已经乱成一团了，我们的生意会不会受影响？","詹"),N("报纸编辑托马斯","普鲁士统一了德国，欧洲的政治格局要变天了。以后德国将成为我们最大的竞争对手。","托")],
[D("d1","太好了，法国战败了，我们英国可以坐收渔利。",68,"你对法国的战败感到幸灾乐祸，认为英国可以坐收渔利。但你很快发现，统一后的德国比法国更难对付，英国的霸权地位受到了挑战。","普法战争后，德国统一，成为欧洲大陆的强国。英国的欧洲大陆均势政策受到挑战，英德矛盾逐渐上升为主要矛盾。","幸灾乐祸，误判形势","act-18"),
D("d2","我担心德国统一后会威胁我们的利益，得早做准备。",85,"你敏锐地意识到，德国统一后将成为英国的强劲对手。你开始研究德国的工业发展，为未来的竞争做准备。","普法战争后，德国工业迅速发展，很快赶上并超过了英国。英德之间的竞争日益激烈，最终导致了第一次世界大战的爆发。","敏锐洞察，提前准备","act-18"),
D("d3","法国的局势很乱，说不定有投资机会。",80,"你从战争中看到了商机，决定趁法国混乱的时候去投资抄底。虽然风险很大，但如果成功，收益也会非常可观。","战争往往会带来投资机会。在战后的混乱中，有眼光的投资者可以低价收购资产，等待经济复苏时获得丰厚回报。","法国抄底，冒险投资","act-18"),
D("d4","我更关心工人运动，战争之后革命会不会爆发？",82,"你更关注战争对工人运动的影响。你知道，战争往往会引发革命。你密切关注着法国的局势，担心革命会蔓延到英国。","战争是革命的催化剂。普法战争直接导致了巴黎公社革命的爆发，对整个欧洲的工人运动都产生了深远的影响。","关注革命，担心蔓延","act-18"),
D("d5","我要扩大生产，趁德国还没发展起来抢占市场。",88,"你决定趁德国还在恢复的时候，大力扩大生产，抢占更多的市场份额。你知道，未来的竞争会越来越激烈，现在必须打好基础。","工业革命时期，市场竞争非常激烈。先下手为强，抢占市场先机，是企业成功的关键。","扩大生产，抢占市场","act-18"),
D("d6","战争太残酷了，我要捐款和平组织，呼吁和平。",85,"你对战争感到厌恶，捐款给和平组织，呼吁各国和平共处。虽然你的呼吁没有阻止战争的爆发，但你为和平事业做出了自己的贡献。","战争给人民带来了深重的灾难。许多有良知的人士致力于和平事业，反对战争，呼吁各国和平共处。","呼吁和平，反对战争","act-18"),
D("d7","我要去德国考察，学习他们的先进经验。",82,"你决定去德国考察，学习他们的工业发展经验。德国的教育体系和技术创新让你印象深刻，你决定把这些经验带回英国。","德国工业的快速发展，得益于其发达的教育体系和重视技术创新。英国的有识之士开始反思，并向德国学习。","考察德国，学习经验","act-18"),
D("d8","战争和我没关系，我继续做我的生意。",70,"你对政治和战争不感兴趣，觉得这些和你没什么关系。你继续经营你的工厂，过着自己的小日子。","并不是所有人都关心国际政治。有些人只关心自己的生意和生活，对外部世界的变化漠不关心。","漠不关心，继续经营","act-18"),
D("d9","我要写本书，分析这场战争的原因和影响。",78,"你对这场战争很感兴趣，决定写一本书分析它的原因和影响。你的书出版后引起了很大反响，你也成了有名的军事评论家。","普法战争是19世纪最重要的战争之一，它改变了欧洲的政治格局。许多学者和评论家都对这场战争进行了深入的研究和分析。","著书立说，分析战争","act-18")]))

# 18 - 关键幕4
acts.append(A("act-18","巴黎公社",True,"1871年",
"1871年3月18日，巴黎公社革命爆发了。巴黎的工人阶级推翻了资产阶级政府，建立了自己的政权——巴黎公社。这是人类历史上第一个无产阶级政权。公社采取了一系列革命措施，打碎旧的国家机器，建立新的人民政权。但是，公社只存在了72天，就在资产阶级的血腥镇压下失败了。",
[N("公社战士皮埃尔","我们建立了自己的政府！公社万岁！工人阶级终于当家作主了！","皮"),N("凡尔赛政府代表梯也尔","这些暴民必须被彻底消灭！我已经向普鲁士借兵了，血洗巴黎！","梯")],
[D("d1","这些工人简直是无法无天！必须血洗巴黎，杀一儆百！",60,"你对巴黎公社恨之入骨，支持凡尔赛政府的血腥镇压。你甚至为镇压者提供了资助。当你得知公社战士被屠杀的消息时，你还拍手称快。","巴黎公社遭到了凡尔赛政府的血腥镇压。据统计，有三万多公社战士被屠杀，五万多人被逮捕或流放。白色恐怖笼罩着整个巴黎。","支持镇压，拍手称快","act-19"),
D("d2","我支持巴黎公社！工人阶级终于站起来了！",92,"你被巴黎公社的革命壮举深深震撼了。你公开表示支持公社，还捐款支援公社的斗争。虽然公社最终失败了，但你坚信，公社的事业是正义的，未来一定会胜利。","巴黎公社虽然只存在了72天，但它是人类历史上第一个无产阶级政权，具有伟大的历史意义。公社的原则是永存的。","支持公社，坚信正义","act-19"),
D("d3","我虽然不赞成革命，但也反对血腥镇压。",85,"你虽然不赞成用革命的方式推翻政府，但更反对资产阶级的血腥屠杀。你公开谴责凡尔赛政府的暴行，呼吁双方和平解决争端。","巴黎公社失败后，凡尔赛政府的血腥镇压遭到了国际进步舆论的强烈谴责。许多资产阶级民主人士也站出来反对这种暴行。","反对屠杀，呼吁和平","act-19"),
D("d4","这是法国人的事，和我们英国有什么关系？",65,"你觉得巴黎公社是法国的内政，和英国没什么关系。你继续过自己的日子，对公社的命运漠不关心。","巴黎公社虽然发生在法国，但它的影响是国际性的。各国工人阶级都从公社的斗争中吸取经验教训。","事不关己，漠不关心","act-19"),
D("d5","我要去巴黎，亲眼见证这段历史。",88,"你决定亲自去巴黎，亲眼见证这场伟大的革命。你亲眼看到了公社战士的英勇斗争，也目睹了凡尔赛军队的残暴。这段经历彻底改变了你的人生。","巴黎公社是19世纪最伟大的历史事件之一。许多进步人士冒着生命危险前往巴黎，亲身参与和见证这场伟大的革命。","亲赴巴黎，见证历史","act-19"),
D("d6","我要收留流亡的公社战士，尽我所能帮助他们。",90,"公社失败后，许多公社战士流亡国外。你伸出了援手，收留了一批流亡到英国的公社战士，为他们提供食宿和工作。","巴黎公社失败后，许多公社战士流亡到英国、比利时等国家。各国的进步人士纷纷伸出援手，帮助这些革命者渡过难关。","收留战士，伸出援手","act-19"),
D("d7","我要研究巴黎公社的经验教训，为以后做准备。",82,"你开始系统地研究巴黎公社的经验教训。你认真阅读公社的文告和法令，分析它失败的原因。这段研究让你对无产阶级革命有了更深的理解。","巴黎公社的经验教训是国际共产主义运动的宝贵财富。马克思在《法兰西内战》中对公社的经验进行了深刻的总结。","研究公社，总结经验","act-19"),
D("d8","幸好我们英国没有发生这样的革命，真是万幸。",68,"你对巴黎公社的革命感到恐惧，暗自庆幸英国没有发生这样的事情。你决定以后要更加小心，防止类似的革命在英国发生。","巴黎公社的革命震撼了整个欧洲的资产阶级。各国资产阶级都加强了对工人运动的镇压，防止革命蔓延到自己的国家。","暗自庆幸，加强防范","act-19"),
D("d9","我要写文章，向英国人民介绍巴黎公社的真相。",85,"你决定写文章，向英国人民介绍巴黎公社的真相，揭露资产阶级媒体的谎言。虽然你的文章遭到了保守势力的攻击，但也让更多的人了解了公社的真实情况。","巴黎公社期间，资产阶级媒体对公社进行了大量的造谣和污蔑。进步的新闻工作者则努力向公众介绍真相，为公社正名。","撰文介绍，揭露谎言","act-19")]))

print(f"第五组生成完成，共 {len(acts)} 幕")

